  'tools.solopreneur-productivity-score.title': { en: 'Productivity Score Calculator', zh: '效率评分计算器' },
  'tools.solopreneur-productivity-score.description': { en: 'Rate your solopreneur productivity with a scored assessment. Get actionable tips based on your deep work hours, tool stack, and meeting load.', zh: '通过评分评估你的创业者效率。根据你的深度工作时间、工具数量和会议负荷获取可操作的改进建议。' },
  'tools.solopreneur-productivity-score.input.weeklyDeepWorkHours.label': { en: 'Weekly Deep Work Hours', zh: '每周深度工作时间' },
  'tools.solopreneur-productivity-score.input.weeklyDeepWorkHours.placeholder': { en: 'e.g. 15', zh: '例如：15' },
  'tools.solopreneur-productivity-score.input.toolsUsed.label': { en: 'Tools / Apps Used Weekly', zh: '每周使用的工具/应用数' },
  'tools.solopreneur-productivity-score.input.toolsUsed.placeholder': { en: 'e.g. 5', zh: '例如：5' },
  'tools.solopreneur-productivity-score.input.meetingsPerWeek.label': { en: 'Meetings Per Week', zh: '每周会议数' },
  'tools.solopreneur-productivity-score.input.meetingsPerWeek.placeholder': { en: 'e.g. 3', zh: '例如：3' },
  'tools.solopreneur-productivity-score.how_to_use.0': { en: 'Enter your total weekly deep work hours (uninterrupted, focused work).', zh: '输入你每周的深度工作总时长（不间断、专注的工作）。' },
  'tools.solopreneur-productivity-score.how_to_use.1': { en: 'Count how many tools/apps you actively use each week.', zh: '统计你每周实际使用的工具/应用数量。' },
  'tools.solopreneur-productivity-score.how_to_use.2': { en: 'Enter your average number of meetings per week.', zh: '输入你每周的平均会议数量。' },
  'tools.solopreneur-productivity-score.how_to_use.3': { en: 'Review your productivity score and grade.', zh: '查看你的效率评分和等级。' },
  'tools.solopreneur-productivity-score.how_to_use.4': { en: 'Read your wins and action items for specific improvements.', zh: '阅读你的优势和行动项，获取具体改进方向。' },
  'tools.solopreneur-productivity-score.faq.0.q': { en: 'What counts as deep work?', zh: '什么算深度工作？' },
  'tools.solopreneur-productivity-score.faq.0.a': { en: 'Deep work = focused, uninterrupted time on your most cognitively demanding tasks (coding, writing, strategy, design). No email, Slack, social media, or phone. 50+ minute blocks minimum.', zh: '深度工作=专注、不被打断地处理最高认知要求的任务（编码、写作、战略、设计）。没有邮件、Slack、社交媒体或手机。每次至少50分钟以上。' },
  'tools.solopreneur-productivity-score.faq.1.q': { en: 'What is a good productivity score?', zh: '多少分算好的效率评分？' },
  'tools.solopreneur-productivity-score.faq.1.a': { en: '70+ is solid. 85+ is excellent. The score is diagnostic — use it to identify your weakest area and improve it over 2-4 weeks.', zh: '70分以上算扎实。85分以上非常出色。这个分数是诊断性的——用来发现你最薄弱的领域，并在2-4周内改善。' },
  'tools.solopreneur-productivity-score.faq.2.q': { en: 'How many tools should an entrepreneur use?', zh: '创业者该用多少个工具？' },
  'tools.solopreneur-productivity-score.faq.2.a': { en: "3-5 core tools is the sweet spot. Every additional tool adds cognitive overhead. Audit quarterly: if you haven't used a tool in 2 weeks, cancel it.", zh: '3-5个核心工具是最佳数量。每增加一个工具都会增加认知负担。每季度审查一次：如果两周没用过某个工具，就取消它。' },
  'tools.solopreneur-productivity-score.faq.3.q': { en: 'Are all meetings bad?', zh: '所有会议都不好吗？' },
  'tools.solopreneur-productivity-score.faq.3.a': { en: 'No — customer calls, sales demos, and 1:1s with contractors are high-value. It is internal status meetings and "quick syncs" that kill productivity. Batch them.', zh: '不是——客户电话、销售演示和与外包人员的一对一沟通是高价值的。是内部状态汇报会和"快速同步"在扼杀效率。把它们集中安排。' },
  'tools.solopreneur-productivity-score.faq.4.q': { en: 'How often should I recalculate my score?', zh: '多久重新计算一次评分？' },
  'tools.solopreneur-productivity-score.faq.4.a': { en: 'Monthly. Track your deep work hours and meeting count for a week, then recalculate. Small changes compound — adding 5 hours of deep work per week is 260 more hours per year.', zh: '每月一次。追踪一周的深度工作时间和会议数量，然后重新计算。小改变会累积——每周增加5小时深度工作，一年就是多了260小时。' },

